import React from "react";

function Filters({ selectedCategories, onChange }) {
  const categories = ["electronics", "men's clothing", "jewelery"];

  return (
    <div>
      <h3>Filters</h3>

      {categories.map((cat) => (
        <div key={cat}>
          <label>
            <input
              type="checkbox"
              checked={selectedCategories.includes(cat)}
              onChange={() => onChange(cat)}
            />
            {" "}{cat}
          </label>
        </div>
      ))}
    </div>
  );
}

export default Filters;
